scwin.gr_result_CustomFormatter = function (data, formattedData, rowIndex, colIndex) {
  let columnId = $c.util.getComponent($p, this.id).getColumnID(colIndex);
  let val = data,
    color = "black";
  if (columnId == "clntClsCd") {
    if (data == "2") {
      val = "농협/축협";
    } else if (data == "1") {
      val = "사협";
    } else {
      val = "개별";
    }
    return val;
  } else if (columnId == "stockWt") {
    if (Number(data) < 0) {
      gr_result.setCellBackgroundColor(rowIndex, columnId, "pink");
    }
    return formattedData;
  }
};
scwin.gr_result_onkeydown = function (e) {
  var keyCode = e.keyCode;
  var rowIdx = this.getFocusedRowIndex();
  var colIdx = this.getFocusedColumnIndex();
  var lastRow = this.getRowCount() - 1;

  // 위(38), 아래(40) 방향키일 때만 실행
  if (keyCode === 38 || keyCode === 40) {
    // [1] 전체 화면 스크롤 방지 (중요!)
    if (e.preventDefault) {
      e.preventDefault();
    } else {
      e.returnValue = false;
    }

    // [2] 편집 모드 강제 종료 및 데이터 반영
    if (typeof this.viewToModel === "function") {
      this.viewToModel();
    }

    // 현재 위치에서 편집 모드 해제 (커서 없애기)
    this.setFocusedCell(rowIdx, colIdx, false);

    // [3] 행 이동 처리
    var nextRow = keyCode === 38 ? rowIdx - 1 : rowIdx + 1;
    if (nextRow >= 0 && nextRow <= lastRow) {
      this.setFocusedCell(nextRow, colIdx, false);

      // [4] 조회 함수 실행 (순서 보장을 위해 딜레이 부여)
      setTimeout(function () {
        if (typeof scwin.f_Retrieve2 === "function") {
          scwin.f_Retrieve2();

          // 보관료상태(01: 진행 / 02:완료 / 03:제외)
          if (ds_result.getCellData(ds_result.getRowPosition(), "strRateStsCd") == "01") {
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "cvsslMgntNo", false); // 본선관리번호
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "scalCommCd", false); // 계근대;품명코드
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "commCd", false); // 데비스;품명코드
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "scalClntNo", false); // 계근대;화주코드
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "clntNo", false); // 데비스;화주코드
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "stockStdAdptDt", false); // 작업;완료일자
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "strRateAdptDt", false); // 보관료;적용일자
            gr_detail.setGridReadOnly(false);
          } else {
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "cvsslMgntNo", true);
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "scalCommCd", true);
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "commCd", true);
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "scalClntNo", true);
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "clntNo", true);
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "stockStdAdptDt", true);
            gr_result.setCellReadOnly(ds_result.getRowPosition(), "strRateAdptDt", true);
            gr_detail.setGridReadOnly(true);
          }
        }
      }, 50);
    }
    return false; // 이벤트 전파 차단
  }
};
